 3→import com.exam.dto.QuestionBatchRequest;
 4→import com.exam.dto.QuestionCreateRequest;
 5→import com.exam.dto.Result;
 6→import com.exam.entity.QuestionBank;
 7→import com.exam.service.QuestionService;
 8→import jakarta.validation.Valid;
 9→import lombok.extern.slf4j.Slf4j;
10→import org.springframework.web.bind.annotation.*;
11→
12→import java.util.List;
13→
14→/**
15→ * 管理员 - 题目管理接口
16→ */
17→@Slf4j
18→@RestController
19→@RequestMapping("/api/admin")
20→public class AdminQuestionController {
21→
22→    private final QuestionService questionService;
23→
24→    public AdminQuestionController(QuestionService questionService) {
25→        this.questionService = questionService;
26→    }
27→
28→    @GetMapping("/exams/{examId}/questions")
29→    public Result<List<QuestionBank>> list(@PathVariable Long examId) {
30→        return Result.ok(questionService.list(examId));
31→    }
32→
33→    @PostMapping("/exams/{examId}/questions")
34→    public Result<QuestionBank> create(@PathVariable Long examId,
35→                                       @Valid @RequestBody QuestionCreateRequest req) {
36→        return Result.ok(questionService.create(examId, req));
37→    }
38→
39→    @PostMapping("/exams/{examId}/questions/batch")
40→    public Result<Integer> batchCreate(@PathVariable Long examId,
41→                                       @Valid @RequestBody QuestionBatchRequest req) {
42→        return Result.ok(questionService.batchCreate(examId, req));
43→    }
44→
45→    @PutMapping("/questions/{id}")
46→    public Result<Void> update(@PathVariable Long id,
47→                               @Valid @RequestBody QuestionCreateRequest req) {
48→        questionService.update(id, req);
49→        return Result.ok();
50→    }
51→
52→    @DeleteMapping("/questions/{id}")
53→    public Result<Void> delete(@PathVariable Long id) {
54→        questionService.delete(id);
55→        return Result.ok();
56→    }
57→}
